0	pub const YAML = struct {
1	    const ParseError = OOM || error{ SyntaxError, StackOverflow };
2	
3	    pub fn parse(source: *const logger.Source, log: *logger.Log, allocator: std.mem.Allocator) ParseError!Expr {
4	        bun.analytics.Features.yaml_parse += 1;
5	
6	        var parser: Parser(.utf8) = .init(allocator, source.contents);
7	
8	        const stream = parser.parse() catch |e| {
9	            const err: Parser(.utf8).ParseResult = .fail(e, &parser);
10	            try err.err.addToLog(source, log);
11	            return error.SyntaxError;
12	        };
13	
14	        return switch (stream.docs.items.len) {
15	            0 => .init(E.Null, .{}, .Empty),
16	            1 => stream.docs.items[0].root,
17	            else => {
18	
19	                // multi-document yaml streams are converted into arrays
20	
21	                var items: bun.BabyList(Expr) = try .initCapacity(allocator, stream.docs.items.len);
22	
23	                for (stream.docs.items) |doc| {
24	                    items.appendAssumeCapacity(doc.root);
25	                }
26	
27	                return .init(E.Array, .{ .items = items }, .Empty);
28	            },
29	        };
30	    }
31	};
