69	                if (close_bracket_idx + 1 < line.len) {
70	                    for (line[close_bracket_idx + 1 ..]) |c| if (switch (c) {
71	                        ' ', '\t' => false,
72	                        else => true,
73	                    }) break :treat_as_key;
74	                }
