import { describe, expect, test } from "bun:test";

describe("Bun.INI", () => {
  test("is defined on Bun", () => {
    expect(Bun.INI).toBeDefined();
    expect(typeof Bun.INI.parse).toBe("function");
    expect(typeof Bun.INI.stringify).toBe("function");
  });

  describe("parse", () => {
    test("basic key=value pairs", () => {
      const result = Bun.INI.parse("key = value\nfoo = bar");
      expect(result).toEqual({ key: "value", foo: "bar" });
    });

    test("key=value without spaces", () => {
      const result = Bun.INI.parse("key=value");
      expect(result).toEqual({ key: "value" });
    });

    test("sections as nested objects", () => {
      const result = Bun.INI.parse(`
[section]
key = value
foo = bar
`);
      expect(result).toEqual({
        section: {
          key: "value",
          foo: "bar",
        },
      });
    });

    test("multiple sections", () => {
      const result = Bun.INI.parse(`
[section1]
a = 1

[section2]
b = 2
`);
      expect(result).toEqual({
        section1: { a: 1 },
        section2: { b: 2 },
      });
    });

    test("top-level and section properties", () => {
      const result = Bun.INI.parse(`
global = yes

[section]
local = no
`);
      expect(result).toEqual({
        global: true,
        section: { local: false },
      });
    });

    test("semicolon comments", () => {
      const result = Bun.INI.parse(`
; this is a comment
key = value
; another comment
`);
      expect(result).toEqual({ key: "value" });
    });

    test("hash comments", () => {
      const result = Bun.INI.parse(`
# this is a comment
key = value
# another comment
`);
      expect(result).toEqual({ key: "value" });
    });

    test("inline comments", () => {
      const result = Bun.INI.parse("key = value ; this is a comment");
      expect(result).toEqual({ key: "value" });
    });

    test("inline hash comments", () => {
      const result = Bun.INI.parse("key = value # this is a comment");
      expect(result).toEqual({ key: "value" });
    });

    test("boolean coercion", () => {
      const result = Bun.INI.parse("a = true\nb = false");
      expect(result).toEqual({ a: true, b: false });
    });

    test("null coercion", () => {
      const result = Bun.INI.parse("a = null");
      expect(result).toEqual({ a: null });
    });

    test("number coercion - integers", () => {
      const result = Bun.INI.parse("a = 42\nb = -7\nc = 0");
      expect(result).toEqual({ a: 42, b: -7, c: 0 });
    });

    test("number coercion - floats", () => {
      const result = Bun.INI.parse("a = 3.14\nb = -0.5");
      expect(result).toEqual({ a: 3.14, b: -0.5 });
    });

    test("quoted strings are not coerced", () => {
      const result = Bun.INI.parse('a = "true"\nb = \'42\'\nc = "null"');
      expect(result).toEqual({ a: "true", b: "42", c: "null" });
    });

    test("empty values", () => {
      const result = Bun.INI.parse("key =");
      expect(result).toEqual({ key: "" });
    });

    test("key without value treated as true", () => {
      const result = Bun.INI.parse("key");
      expect(result).toEqual({ key: true });
    });

    test("empty string returns empty object", () => {
      const result = Bun.INI.parse("");
      expect(result).toEqual({});
    });

    test("only comments and empty lines", () => {
      const result = Bun.INI.parse(`
; comment
# another comment

`);
      expect(result).toEqual({});
    });

    test("values with equals sign", () => {
      const result = Bun.INI.parse("equation = 1+1=2");
      expect(result).toEqual({ equation: "1+1=2" });
    });

    test("whitespace handling", () => {
      const result = Bun.INI.parse("  key  =  value  ");
      expect(result).toEqual({ key: "value" });
    });

    test("CRLF line endings", () => {
      const result = Bun.INI.parse("[section]\r\nkey = value\r\n");
      expect(result).toEqual({ section: { key: "value" } });
    });

    test("leading zeros are strings, not numbers", () => {
      const result = Bun.INI.parse("a = 007\nb = 0123");
      expect(result).toEqual({ a: "007", b: "0123" });
    });

    test("hex numbers", () => {
      const result = Bun.INI.parse("a = 0xFF");
      // hex is not coerced to number in standard INI
      expect(result).toEqual({ a: "0xFF" });
    });

    test("same section appearing twice merges", () => {
      const result = Bun.INI.parse(`
[section]
a = 1

[section]
b = 2
`);
      expect(result).toEqual({ section: { a: 1, b: 2 } });
    });

    test("throws on non-string input", () => {
      expect(() => (Bun.INI.parse as any)()).toThrow();
    });
  });

  describe("stringify", () => {
    test("basic key=value pairs", () => {
      const result = Bun.INI.stringify({ key: "value", foo: "bar" });
      expect(result).toBe("key = value\nfoo = bar\n");
    });

    test("sections", () => {
      const result = Bun.INI.stringify({
        section: { key: "value" },
      });
      expect(result).toContain("[section]");
      expect(result).toContain("key = value");
    });

    test("top-level and section mixed", () => {
      const result = Bun.INI.stringify({
        global: "yes",
        section: { key: "value" },
      });
      // Top-level comes first
      expect(result.indexOf("global")).toBeLessThan(result.indexOf("[section]"));
    });

    test("boolean values", () => {
      const result = Bun.INI.stringify({ a: true, b: false });
      expect(result).toBe("a = true\nb = false\n");
    });

    test("null value", () => {
      const result = Bun.INI.stringify({ a: null });
      expect(result).toBe("a = null\n");
    });

    test("number values", () => {
      const result = Bun.INI.stringify({ a: 42, b: 3.14 });
      expect(result).toContain("a = 42");
      expect(result).toContain("b = 3.14");
    });

    test("array values as repeated keys", () => {
      const result = Bun.INI.stringify({ items: [1, 2, 3] });
      expect(result).toContain("items[] = 1");
      expect(result).toContain("items[] = 2");
      expect(result).toContain("items[] = 3");
    });

    test("strings that look like booleans are quoted", () => {
      const result = Bun.INI.stringify({ val: "true" });
      expect(result).toContain('"true"');
    });

    test("strings that look like numbers are quoted", () => {
      const result = Bun.INI.stringify({ val: "42" });
      expect(result).toContain('"42"');
    });

    test("strings that look like null are quoted", () => {
      const result = Bun.INI.stringify({ val: "null" });
      expect(result).toContain('"null"');
    });

    test("empty object", () => {
      const result = Bun.INI.stringify({});
      expect(result).toBe("");
    });

    test("skips undefined values", () => {
      const result = Bun.INI.stringify({ a: "hello", b: undefined } as any);
      expect(result).toBe("a = hello\n");
      expect(result).not.toContain("b");
    });

    test("throws on non-object input", () => {
      expect(() => (Bun.INI.stringify as any)("string")).toThrow();
    });
  });

  describe("round-trip", () => {
    test("simple object round-trips", () => {
      const obj = { key: "value", num: 42, flag: true };
      const str = Bun.INI.stringify(obj);
      const parsed = Bun.INI.parse(str);
      expect(parsed).toEqual(obj);
    });

    test("object with sections round-trips", () => {
      const obj = {
        section: { key: "value", num: 42, flag: true },
      };
      const str = Bun.INI.stringify(obj);
      const parsed = Bun.INI.parse(str);
      expect(parsed).toEqual(obj);
    });

    test("mixed top-level and sections round-trips", () => {
      const obj = {
        global: "hello",
        section: { a: 1, b: false },
      };
      const str = Bun.INI.stringify(obj);
      const parsed = Bun.INI.parse(str);
      expect(parsed).toEqual(obj);
    });
  });
});

