pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argumentsAsArray(1)[0];

    value.ensureStillAlive();

    if (!value.isObject() or value.isFunction()) {
        return global.throw("INI.stringify expects an object argument", .{});
    }

    var s: INIStringifier = .init();
    defer s.deinit();

    try s.stringifyTopLevel(global, value);

    return s.builder.toString(global);
}

pub fn parse(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callFrame.argumentsAsArray(1)[0];

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected a string to parse", .{});
    }

    var str = try input_value.toBunString(global);
    defer str.deref();

    var scope: bun.AllocationScope = .init(bun.default_allocator);
    defer scope.deinit();

    const slice = str.toSlice(scope.allocator());

    return parseINI(global, slice.slice());
}

fn parseINI(global: *jsc.JSGlobalObject, src: []const u8) bun.JSError!jsc.JSValue {
    const root = JSValue.createEmptyObject(global, 0);
    var current_section = root;

    var iter = std.mem.splitScalar(u8, src, '\n');
    while (iter.next()) |raw_line| {
        // Handle \r\n line endings
        const line_no_cr = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
            raw_line[0 .. raw_line.len - 1]
        else
            raw_line;

        const line = bun.strings.trimSpaces(line_no_cr);

        // Skip empty lines and comments
        if (line.len == 0) continue;
        if (line[0] == ';' or line[0] == '#') continue;

        // Section header: [section]
        if (line[0] == '[') {
            if (std.mem.indexOfScalar(u8, line, ']')) |close_idx| {
                // Verify rest of line after ']' is whitespace or comment
                const after_bracket = bun.strings.trimSpaces(line[close_idx + 1 ..]);
                if (after_bracket.len == 0 or after_bracket[0] == ';' or after_bracket[0] == '#') {
                    const section_name = bun.strings.trimSpaces(line[1..close_idx]);
                    if (section_name.len > 0) {
                        // Check if section already exists
                        const existing = try root.get(global, section_name);
