const INIStringifier = struct {
    stack_check: bun.StackCheck,
    builder: wtf.StringBuilder,

    const StringifyError = bun.JSError || bun.StackOverflow;

    pub fn init() INIStringifier {
        return .{
            .stack_check = .init(),
            .builder = .init(),
        };
    }

    pub fn deinit(this: *INIStringifier) void {
        this.builder.deinit();
    }

    pub fn stringifyTopLevel(this: *INIStringifier, global: *jsc.JSGlobalObject, value: jsc.JSValue) StringifyError!void {
        // First pass: emit all non-object top-level properties
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        var had_top_level = false;

        while (try iter.next()) |prop_name| {
            if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
                continue;
            }

            if (iter.value.isObject() and !iter.value.isArray() and !iter.value.isFunction()) {
                continue; // Skip objects (sections) in first pass
            }

            try this.appendKeyValue(global, prop_name, iter.value);
            had_top_level = true;
        }

        // Second pass: emit sections (object-valued properties)
        var iter2: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter2.deinit();

        while (try iter2.next()) |prop_name| {
            if (iter2.value.isUndefined() or iter2.value.isSymbol() or iter2.value.isFunction()) {
                continue;
            }

            if (!iter2.value.isObject() or iter2.value.isArray() or iter2.value.isFunction()) {
                continue; // Skip non-objects (handled in first pass)
            }

            // Add blank line before section (if there was previous content)
            if (had_top_level or this.builder.len() > 0) {
                this.builder.append(.lchar, '\n');
            }

            // Section header
            this.builder.append(.lchar, '[');
            this.builder.append(.string, prop_name);
            this.builder.append(.latin1, "]\n");

            // Section properties
            try this.stringifySection(global, iter2.value);
            had_top_level = true;
        }
    }

    fn stringifySection(this: *INIStringifier, global: *jsc.JSGlobalObject, value: jsc.JSValue) StringifyError!void {
        if (!this.stack_check.isSafeToRecurse()) {
            return error.StackOverflow;
        }

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
                continue;
            }

            try this.appendKeyValue(global, prop_name, iter.value);
        }
    }

    fn appendKeyValue(this: *INIStringifier, global: *jsc.JSGlobalObject, key: bun.String, value: jsc.JSValue) StringifyError!void {
        if (value.isArray()) {
            // Arrays: emit multiple lines with key[]=value
            var arr_iter = try value.arrayIterator(global);
            while (try arr_iter.next()) |item| {
                this.builder.append(.string, key);
                this.builder.append(.latin1, "[] = ");
                try this.appendValue(global, item);
                this.builder.append(.lchar, '\n');
            }
            return;
        }

        this.builder.append(.string, key);
        this.builder.append(.latin1, " = ");
        try this.appendValue(global, value);
        this.builder.append(.lchar, '\n');
    }

    fn appendValue(this: *INIStringifier, global: *jsc.JSGlobalObject, value: jsc.JSValue) StringifyError!void {
        if (value.isNull()) {
            this.builder.append(.latin1, "null");
            return;
        }

        if (value.isBoolean()) {
            this.builder.append(.latin1, if (value.asBoolean()) "true" else "false");
            return;
        }

        if (value.isNumber()) {
            if (value.isInt32()) {
                this.builder.append(.int, value.asInt32());
            } else {
                this.builder.append(.double, value.asNumber());
            }
            return;
        }

        if (value.isString()) {
            const str = try value.toBunString(global);
            defer str.deref();
            this.appendINIString(str);
            return;
        }

        // For other types (nested objects that aren't sections), use toString
        const str = try value.toBunString(global);
        defer str.deref();
        this.builder.append(.string, str);
    }

    fn appendINIString(this: *INIStringifier, str: bun.String) void {
        // Check if the string needs quoting
        const needs_quoting = needs_quoting: {
            if (str.length() == 0) break :needs_quoting false;

            // Check for characters that have special meaning in INI
            for (0..str.length()) |i| {
                const c = str.charAt(i);
                switch (c) {
                    ';', '#', '=', '\n', '\r' => break :needs_quoting true,
                    else => {},
                }
