pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argumentsAsArray(1)[0];

    value.ensureStillAlive();

    if (!value.isObject() or value.isFunction()) {
        return global.throw("INI.stringify expects an object argument", .{});
    }

    var s: INIStringifier = .init();
    defer s.deinit();

    try s.stringifyTopLevel(global, value);

    return s.builder.toString(global);
}

pub fn parse(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callFrame.argumentsAsArray(1)[0];

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected a string to parse", .{});
    }

    var str = try input_value.toBunString(global);
    // toSlice transfers ownership of the string ref into the returned SliceWithUnderlyingString.
    // After toSlice, str is .empty — deinit on the slice handles cleanup of both utf8 and underlying.
    var slice = str.toSlice(bun.default_allocator);
    defer slice.deinit();

    return parseINI(global, slice.slice());
}

fn parseINI(global: *jsc.JSGlobalObject, src: []const u8) bun.JSError!jsc.JSValue {
    const root = JSValue.createEmptyObject(global, 0);
    var current_section = root;

    var iter = std.mem.splitScalar(u8, src, '\n');
    while (iter.next()) |raw_line| {
        // Handle \r\n line endings
        const line_no_cr = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
            raw_line[0 .. raw_line.len - 1]
        else
            raw_line;

        const line = bun.strings.trimSpaces(line_no_cr);

        // Skip empty lines and comments
        if (line.len == 0) continue;
        if (line[0] == ';' or line[0] == '#') continue;

        // Section header: [section]
        if (line[0] == '[') {
            if (std.mem.indexOfScalar(u8, line, ']')) |close_idx| {
                // Verify rest of line after ']' is whitespace or comment
                const after_bracket = bun.strings.trimSpaces(line[close_idx + 1 ..]);
                if (after_bracket.len == 0 or after_bracket[0] == ';' or after_bracket[0] == '#') {
                    const section_name = bun.strings.trimSpaces(line[1..close_idx]);
                    if (section_name.len > 0) {
                        // Check if section already exists
                        const existing = try root.get(global, section_name);
                        if (existing) |val| {
                            if (val.isObject()) {
                                current_section = val;
                                continue;
                            }
                        }
                        const section_obj = JSValue.createEmptyObject(global, 0);
                        root.put(global, section_name, section_obj);
                        current_section = section_obj;
                        continue;
                    }
                }
            }
            // If we can't parse it as a section, fall through to key=value parsing
        }

        // Key=value pair
        if (std.mem.indexOfScalar(u8, line, '=')) |eq_idx| {
            const raw_key = bun.strings.trimSpaces(line[0..eq_idx]);
            if (raw_key.len == 0) continue;

            const raw_value = bun.strings.trimSpaces(line[eq_idx + 1 ..]);

            // Remove inline comments (only if preceded by whitespace)
            const value_str = stripInlineComment(raw_value);

            const js_value = try coerceValue(global, value_str);
            current_section.put(global, raw_key, js_value);
        } else {
            // Key without value - treat as true (like npm ini)
            const raw_key = bun.strings.trimSpaces(line);
            if (raw_key.len > 0) {
                current_section.put(global, raw_key, JSValue.jsBoolean(true));
            }
        }
    }

    return root;
}

/// Strip inline comments: ` ; comment` or ` # comment`
/// Only strips if the comment character is preceded by whitespace.
/// Also unquotes quoted strings.
fn stripInlineComment(value: []const u8) []const u8 {
    // Handle quoted strings - don't strip comments inside quotes
    if (value.len >= 2) {
        if ((value[0] == '"' and value[value.len - 1] == '"') or
            (value[0] == '\'' and value[value.len - 1] == '\''))
        {
            // Return the unquoted content
            return value[1 .. value.len - 1];
        }
    }

    // Find inline comment (preceded by whitespace)
    var i: usize = 1; // Start at 1 since we need a preceding char
    while (i < value.len) : (i += 1) {
        if ((value[i] == ';' or value[i] == '#') and
            (value[i - 1] == ' ' or value[i - 1] == '\t'))
        {
            return bun.strings.trimSpaces(value[0 .. i - 1]);
        }
    }

    return value;
}

/// Coerce a string value to the appropriate JS type
fn coerceValue(global: *jsc.JSGlobalObject, value: []const u8) bun.JSError!jsc.JSValue {
    // Handle quoted strings - return as-is (no coercion)
    if (value.len >= 2) {
        if ((value[0] == '"' and value[value.len - 1] == '"') or
            (value[0] == '\'' and value[value.len - 1] == '\''))
        {
            const unquoted = value[1 .. value.len - 1];
            return bun.String.createUTF8ForJS(global, unquoted);
        }
    }

    if (value.len == 0) {
        return bun.String.createUTF8ForJS(global, "");
    }

    // Boolean
    if (bun.strings.eqlComptime(value, "true")) return JSValue.jsBoolean(true);
    if (bun.strings.eqlComptime(value, "false")) return JSValue.jsBoolean(false);

    // Null
    if (bun.strings.eqlComptime(value, "null")) return JSValue.jsNull();

    // Try parsing as number
    if (parseNumber(value)) |num| {
        return JSValue.jsNumber(num);
    }

    return bun.String.createUTF8ForJS(global, value);
}

/// Try to parse a string as a number (integer or float).
/// Rejects leading-zero numbers like "007" (treated as strings in INI).
fn parseNumber(value: []const u8) ?f64 {
    if (value.len == 0) return null;

    // Reject strings with leading zeros (like "007", "0123") — they're not numbers in INI.
    // Allow "0", "0.5", etc.
    if (value.len > 1 and value[0] == '0' and value[1] != '.') {
        return null;
    }
    // Same for negative leading zeros: "-007"
    if (value.len > 2 and value[0] == '-' and value[1] == '0' and value[2] != '.') {
        return null;
    }

    // Try integer parse first
    if (std.fmt.parseInt(i64, value, 10)) |int_val| {
        return @floatFromInt(int_val);
    } else |_| {}

    // Try float parse
    if (std.fmt.parseFloat(f64, value)) |float_val| {
        if (!std.math.isNan(float_val) and !std.math.isInf(float_val)) {
            return float_val;
        }
    } else |_| {}

    return null;
}

// -- Stringifier --

const INIStringifier = struct {
    stack_check: bun.StackCheck,
    builder: wtf.StringBuilder,

    const StringifyError = bun.JSError || bun.StackOverflow;

    pub fn init() INIStringifier {
        return .{
            .stack_check = .init(),
            .builder = .init(),
        };
    }

    pub fn deinit(this: *INIStringifier) void {
        this.builder.deinit();
    }

    pub fn stringifyTopLevel(this: *INIStringifier, global: *jsc.JSGlobalObject, value: jsc.JSValue) StringifyError!void {
        // First pass: emit all non-object top-level properties
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        var had_top_level = false;

        while (try iter.next()) |prop_name| {
            if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
                continue;
            }

            if (iter.value.isObject() and !iter.value.isArray() and !iter.value.isFunction()) {
                continue; // Skip objects (sections) in first pass
            }

            try this.appendKeyValue(global, prop_name, iter.value);
            had_top_level = true;
        }

        // Second pass: emit sections (object-valued properties)
        var iter2: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter2.deinit();

        while (try iter2.next()) |prop_name| {
            if (iter2.value.isUndefined() or iter2.value.isSymbol() or iter2.value.isFunction()) {
                continue;
            }

            if (!iter2.value.isObject() or iter2.value.isArray() or iter2.value.isFunction()) {
                continue; // Skip non-objects (handled in first pass)
            }

            // Add blank line before section (if there was previous content)
            if (had_top_level) {
                this.builder.append(.lchar, '\n');
            }

            // Section header
            this.builder.append(.lchar, '[');
            this.builder.append(.string, prop_name);
            this.builder.append(.latin1, "]\n");

            // Section properties
            try this.stringifySection(global, iter2.value);
            had_top_level = true;
        }
    }

    fn stringifySection(this: *INIStringifier, global: *jsc.JSGlobalObject, value: jsc.JSValue) StringifyError!void {
        if (!this.stack_check.isSafeToRecurse()) {
            return error.StackOverflow;
        }

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
                continue;
            }

            try this.appendKeyValue(global, prop_name, iter.value);
        }
    }

    fn appendKeyValue(this: *INIStringifier, global: *jsc.JSGlobalObject, key: bun.String, value: jsc.JSValue) StringifyError!void {
        if (value.isArray()) {
            // Arrays: emit multiple lines with key[]=value
            var arr_iter = try value.arrayIterator(global);
            while (try arr_iter.next()) |item| {
                this.builder.append(.string, key);
                this.builder.append(.latin1, "[] = ");
                try this.appendValue(global, item);
                this.builder.append(.lchar, '\n');
            }
            return;
        }

        this.builder.append(.string, key);
        this.builder.append(.latin1, " = ");
        try this.appendValue(global, value);
        this.builder.append(.lchar, '\n');
    }

    fn appendValue(this: *INIStringifier, global: *jsc.JSGlobalObject, value: jsc.JSValue) StringifyError!void {
        if (value.isNull()) {
            this.builder.append(.latin1, "null");
            return;
        }

        if (value.isBoolean()) {
            this.builder.append(.latin1, if (value.asBoolean()) "true" else "false");
            return;
        }

        if (value.isNumber()) {
            if (value.isInt32()) {
                this.builder.append(.int, value.asInt32());
            } else {
                this.builder.append(.double, value.asNumber());
            }
            return;
        }

        if (value.isString()) {
            const str = try value.toBunString(global);
            defer str.deref();
            this.appendINIString(str);
            return;
        }

        // For other types (nested objects that aren't sections), use toString
        const str = try value.toBunString(global);
        defer str.deref();
        this.builder.append(.string, str);
    }

    fn appendINIString(this: *INIStringifier, str: bun.String) void {
        // Check if the string needs quoting
        const needs_quoting = needs_quoting: {
            if (str.length() == 0) break :needs_quoting false;

            // Check for characters that have special meaning in INI
            for (0..str.length()) |i| {
                const c = str.charAt(i);
                switch (c) {
                    ';', '#', '=', '\n', '\r' => break :needs_quoting true,
                    else => {},
                }
            }

            // Check if it looks like a boolean, null, or number
            const utf8 = str.toSlice(bun.default_allocator);
            defer utf8.deinit();
            const s = utf8.slice();

            if (bun.strings.eqlComptime(s, "true") or
                bun.strings.eqlComptime(s, "false") or
                bun.strings.eqlComptime(s, "null"))
            {
                break :needs_quoting true;
            }

            if (parseNumber(s) != null) {
                break :needs_quoting true;
            }

            // Check for leading/trailing whitespace
            if (s.len > 0 and (s[0] == ' ' or s[0] == '\t' or s[s.len - 1] == ' ' or s[s.len - 1] == '\t')) {
                break :needs_quoting true;
            }

            break :needs_quoting false;
        };

        if (needs_quoting) {
            this.builder.append(.lchar, '"');
            this.builder.append(.string, str);
            this.builder.append(.lchar, '"');
        } else {
            this.builder.append(.string, str);
        }
    }
};

